const oauthConfig = {
    clientId: 'YOUR_CLIENT_ID',
    redirectUri: 'YOUR_REDIRECT_URI',
    authUrl: 'https://authorization-server.com/oauth/authorize',
    apiUrl: 'https://api-server.com/resource',
    scopes: 'YOUR_SCOPES',
};

function redirectToAuth() {
    const authUrl = `${oauthConfig.authUrl}?response_type=token&client_id=${oauthConfig.clientId}&redirect_uri=${encodeURIComponent(oauthConfig.redirectUri)}&scope=${encodeURIComponent(oauthConfig.scopes)}`;
    window.location.href = authUrl;
}

function parseAccessToken() {
    const hash = window.location.hash;
    const regex = /#access_token=([^&]*)/;
    const match = hash.match(regex);
    if (match) {
        return match[1];
    }
    return null;
}

function storeAccessToken(token) {
    sessionStorage.setItem('access_token', token);
}

function getAccessToken() {
    return sessionStorage.getItem('access_token');
}

function apiCall() {
    const token = getAccessToken();
    if (!token) {
        console.error('No access token available. Redirecting to authentication.');
        redirectToAuth();
        return;
    }

    fetch(oauthConfig.apiUrl, {
        method: 'GET',
        headers: {
            'Authorization': `Bearer ${token}`,
        },
    })
    .then(response => response.json())
    .then(data => {
        console.log('API response:', data);
    })
    .catch(error => {
        console.error('API call error:', error);
    });
}

// Check for access token and store it if present
const token = parseAccessToken();
if (token) {
    storeAccessToken(token);
    window.location.hash = ''; // Clean up the URL
}

// Call the API
apiCall();